module RefModule(
    input clk,
    input reset,
    output reg [4:0] q
    );

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
    begin
        if (reset)
            q <= 5'b0;
        else
            q <= q + 1;
    end

endmodule
